/**
 * Vercel Serverless API (Simplified)
 *
 * Serves as a health check and data proxy for the options analysis app.
 * All options data is pre-generated by the GitHub Actions workflow and
 * served as a static JSON file from /data/options_data.json.
 *
 * @module api/index
 */

import type { VercelRequest, VercelResponse } from '@vercel/node';

export default async function handler(req: VercelRequest, res: VercelResponse) {
  // CORS headers
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

  // Handle preflight
  if (req.method === 'OPTIONS') {
    return res.status(204).end();
  }

  // Only allow GET
  if (req.method !== 'GET') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  // Handle live spot prices request
  if (req.query.action === 'spot') {
    try {
      // Fetch SPY and QQQ quotes in parallel with pre-market data
      const symbols = ['SPY', 'QQQ'];
      const quotes = await Promise.all(
        symbols.map(async (symbol) => {
          try {
            const response = await fetch(
              `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(symbol)}?interval=1m&range=1d&includePrePost=true`,
              {
                headers: {
                  'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'
                }
              }
            );
            if (!response.ok) throw new Error(`HTTP ${response.status}`);
            const data = await response.json();
            const result = data?.chart?.result?.[0];
            const meta = result?.meta;
            const closes = result?.indicators?.quote?.[0]?.close || [];
            
            let price = null;
            for (let i = closes.length - 1; i >= 0; i--) {
              if (closes[i] !== null && closes[i] !== undefined) {
                price = closes[i];
                break;
              }
            }
            if (price === null) {
              price = meta?.regularMarketPrice || null;
            }
            return { symbol, price };
          } catch (err) {
            console.error(`Error fetching ${symbol}:`, err);
            return { symbol, price: null };
          }
        })
      );

      const spyPrice = quotes.find(q => q.symbol === 'SPY')?.price || null;
      const qqqPrice = quotes.find(q => q.symbol === 'QQQ')?.price || null;

      // Use standard completed-close cash ratios to derive index spot prices
      const SPX_SPY_RATIO = 10.024;
      const NDX_QQQ_RATIO = 41.121;

      const spotData = {
        SPX: spyPrice ? Number((spyPrice * SPX_SPY_RATIO).toFixed(2)) : null,
        NDX: qqqPrice ? Number((qqqPrice * NDX_QQQ_RATIO).toFixed(2)) : null,
        SPY: spyPrice,
        QQQ: qqqPrice,
        timestamp: new Date().toISOString()
      };

      return res.status(200).json(spotData);
    } catch (error) {
      return res.status(500).json({ error: 'Failed to fetch spot prices', details: String(error) });
    }
  }

  // Health check / status endpoint
  return res.status(200).json({
    status: 'ok',
    service: 'options-wall-analyzer',
    timestamp: new Date().toISOString(),
    dataUrl: '/data/options_data.json',
  });
}
